"use client";

import { useState, useEffect } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { GoogleAuthProvider, signInWithPopup } from "firebase/auth";
import { useRouter, useSearchParams } from "next/navigation";
import { auth } from "@/lib/firebase";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Toaster } from "@/components/ui/toaster";
import { WalletCards, Bell, LockKeyhole, Fingerprint, AtSign, BarChart4 } from "lucide-react";

type Screen = "splash" | "welcome" | "login" | "pin";

export default function HomePageClient() {
  const [screen, setScreen] = useState<Screen>("splash");
  const [pin, setPin] = useState("");
  const [pinError, setPinError] = useState("");
  const router = useRouter();
  const { toast } = useToast();
  const searchParams = useSearchParams();

  useEffect(() => {
    if (searchParams.get('cleared') === 'true') {
        localStorage.removeItem("bill_tracker_pin");
        localStorage.removeItem("bill_tracker_user");
    }

    if (localStorage.getItem("bill_tracker_pin")) {
      setScreen("pin");
    } else {
      const timer1 = setTimeout(() => setScreen("welcome"), 3000);
      const timer2 = setTimeout(() => setScreen("login"), 6000);
      return () => {
        clearTimeout(timer1);
        clearTimeout(timer2);
      };
    }
  }, [searchParams]);

  const handleGoogleLogin = async () => {
    const provider = new GoogleAuthProvider();
    try {
      const result = await signInWithPopup(auth, provider);
      localStorage.setItem("bill_tracker_user", JSON.stringify(result.user));
      router.push("/dashboard");
    } catch (error) {
      console.error("Google Sign-In Error:", error);
      toast({
        variant: "destructive",
        title: "Login Failed",
        description: "Could not sign you in with Google. Please try again.",
      });
    }
  };

  const handleSkipLogin = () => {
    localStorage.removeItem("bill_tracker_user");
    router.push("/dashboard");
  };

  const handlePinLogin = () => {
    const storedPin = localStorage.getItem("bill_tracker_pin");
    if (pin === storedPin) {
      router.push("/dashboard");
    } else {
      setPinError("Invalid PIN. Please try again.");
      setPin("");
    }
  };
  
  const screenVariants = {
    initial: { opacity: 0, scale: 0.95 },
    animate: { opacity: 1, scale: 1 },
    exit: { opacity: 0, scale: 0.95 },
  };

  return (
    <div className="flex h-screen w-full items-center justify-center bg-background p-4">
      <Toaster />
      <AnimatePresence mode="wait">
        {screen === "splash" && (
          <motion.div
            key="splash"
            variants={screenVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            transition={{ duration: 0.5 }}
            className="flex flex-col items-center text-center"
          >
            <WalletCards className="h-24 w-24 text-primary" />
            <h1 className="mt-4 text-4xl font-bold text-foreground">Offline Bill Boss</h1>
            <p className="text-muted-foreground">aaryan-os-app-pv1</p>
          </motion.div>
        )}

        {screen === "welcome" && (
          <motion.div
            key="welcome"
            variants={screenVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            transition={{ duration: 0.5 }}
            className="flex flex-col items-center text-center"
          >
            <h1 className="text-2xl font-semibold text-foreground">Welcome to My Bill Tracker 📊</h1>
            <p className="mt-2 text-muted-foreground">Support me so I can launch it on Play Store 🙏</p>
          </motion.div>
        )}

        {screen === "login" && (
          <motion.div
            key="login"
            variants={screenVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            transition={{ duration: 0.5 }}
          >
            <Card className="w-full max-w-sm">
              <CardHeader className="text-center">
                <CardTitle className="text-2xl">Login</CardTitle>
                <CardDescription>Sign in to get started</CardDescription>
              </CardHeader>
              <CardContent className="grid gap-4">
                <Button onClick={handleGoogleLogin} className="w-full">
                  <svg className="mr-2 h-4 w-4" aria-hidden="true" focusable="false" data-prefix="fab" data-icon="google" role="img" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 488 512"><path fill="currentColor" d="M488 261.8C488 403.3 391.1 504 248 504 110.8 504 0 393.2 0 256S110.8 8 248 8c66.8 0 126 23.4 172.9 61.9l-62.2 62.2C337.9 99.9 294.9 84 248 84c-80.9 0-146.5 65.5-146.5 146.4s65.6 146.4 146.5 146.4c97.4 0 134.1-66.2 140.4-101.9H248v-73.8h235.5c4.8 26.2 7.5 54.5 7.5 85.8z"></path></svg>
                  Sign in with Google
                </Button>
                <Button variant="link" onClick={handleSkipLogin}>
                  Skip login (offline mode)
                </Button>
              </CardContent>
            </Card>
          </motion.div>
        )}
        
        {screen === "pin" && (
           <motion.div
             key="pin"
             variants={screenVariants}
             initial="initial"
             animate="animate"
             exit="exit"
             transition={{ duration: 0.5 }}
           >
            <Card className="w-full max-w-sm">
              <CardHeader className="text-center">
                <CardTitle className="text-2xl">Enter PIN</CardTitle>
                <CardDescription>Enter your PIN to unlock.</CardDescription>
              </CardHeader>
              <CardContent className="grid gap-4">
                <div className="grid gap-2">
                  <Label htmlFor="pin">PIN</Label>
                  <Input 
                    id="pin" 
                    type="password" 
                    value={pin}
                    onChange={(e) => {
                        setPin(e.target.value);
                        setPinError("");
                    }}
                    onKeyDown={(e) => e.key === 'Enter' && handlePinLogin()}
                    />
                </div>
                {pinError && <p className="text-sm text-destructive">{pinError}</p>}
                <Button onClick={handlePinLogin} className="w-full">Unlock</Button>
                 <Button variant="link" onClick={() => router.push('/?cleared=true')}>
                  Forgot PIN? Log in another way.
                </Button>
              </CardContent>
            </Card>
           </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
